function applyZoom() {
    if (fitScreen) {
        canvas.style.width = "100%";
        canvas.style.height = "auto";
    } else {
        canvas.style.width = `${canvas.width * zoomLevel}px`;
        canvas.style.height = `${canvas.height * zoomLevel}px`;
    }
}

